    uint64_t r15_1 = *(Overlay_1 + 0x18);          // total_returned_length
    void* rbp_2 = *(Overlay_1 + 8) + MappedSystemVa_1;  // buffer + offset
    int16_t rbx_1 = *(rbp_2 + 8) + 2;               // length field from returned data + 2

    if (!EvaluateCurrentState(&g_Feature_499346745_59190809))  // DEFAULT PATH (flag OFF), sub_1c0015714
    {
